    29	struct AllocaInfo
    30	{
    31	  SmallVector<BasicBlock*, 32> DefiningBlocks;
    32	  SmallVector<BasicBlock*, 32> UsingBlocks;
    33	
    34	  StoreInst* OnlyStore;
    35	  BasicBlock* OnlyBlock;
    36	  bool OnlyUsedInOneBlock;
    37	
    38	  void clear()
    39	  {
    40	    DefiningBlocks.clear();
    41	    UsingBlocks.clear();
    42	    OnlyStore = nullptr;
    43	    OnlyBlock = nullptr;
    44	    OnlyUsedInOneBlock = true;
