    47	  /// Scan the uses of the specified alloca, filling in the AllocaInfo used
    48	  /// by the rest of the pass to reason about the uses of this alloca.
    49	  void AnalyzeAlloca(AllocaInst* AI)
    50	  {
    51	    clear();
    52	
    53	    // As we scan the uses of the alloca instruction, keep track of stores,
    54	    // and decide whether all of the loads and stores to the alloca are within
    55	    // the same basic block.
    56	    for (User* U : AI->users()) {
    57	      Instruction* User = cast<Instruction>(U);
    58	
    59	      if (StoreInst* SI = dyn_cast<StoreInst>(User)) {
    60	        // Remember the basic blocks which define new values for the alloca
    61	        DefiningBlocks.push_back(SI->getParent());
    62	        OnlyStore = SI;
    63	      } else {
    64	        LoadInst* LI = cast<LoadInst>(User);
    65	        // Otherwise it must be a load instruction, keep track of variable
    66	        // reads.
    67	        UsingBlocks.push_back(LI->getParent());
    68	      }
    69	
    70	      if (OnlyUsedInOneBlock) {
    71	        if (!OnlyBlock)
    72	          OnlyBlock = User->getParent();
    73	        else if (OnlyBlock != User->getParent())
    74	          OnlyUsedInOneBlock = false;
    75	      }
    76	    }
    77	  }
    78	};
