   168	/// This assigns and keeps a per-bb relative ordering of load/store
   169	/// instructions in the block that directly load or store an alloca.
   170	///
   171	/// This functionality is important because it avoids scanning large basic
   172	/// blocks multiple times when promoting many allocas in the same block.
   173	class LargeBlockInfo
   174	{
   175	  /// For each instruction that we track, keep the index of the
   176	  /// instruction.
   177	  ///
   178	  /// The index starts out as the number of the instruction from the start of
   179	  /// the block.
   180	  DenseMap<const Instruction*, unsigned> InstNumbers;
   181	
   182	public:
   183	  /// This code only looks at accesses to allocas.
   184	  static bool isInterestingInstruction(const Instruction* I)
   185	  {
   186	    return (isa<LoadInst>(I) && isa<AllocaInst>(I->getOperand(0))) ||
   187	           (isa<StoreInst>(I) && isa<AllocaInst>(I->getOperand(1)));
   188	  }
   189	
   190	  /// Get or calculate the index of the specified instruction.
   191	  unsigned getInstructionIndex(const Instruction* I)
   192	  {
   193	    assert(isInterestingInstruction(I) &&
   194	           "Not a load/store to/from an alloca?");
   195	
   196	    // If we already have this instruction number, return it.
   197	    DenseMap<const Instruction*, unsigned>::iterator It = InstNumbers.find(I);
   198	    if (It != InstNumbers.end())
   199	      return It->second;
   200	
   201	    // Scan the whole block to get the instruction.  This accumulates
   202	    // information for every interesting instruction in the block, in order to
   203	    // avoid gratuitus rescans.
   204	    const BasicBlock* BB = I->getParent();
   205	    unsigned InstNo = 0;
   206	    for (const Instruction& BBI : *BB)
   207	      if (isInterestingInstruction(&BBI))
   208	        InstNumbers[&BBI] = InstNo++;
   209	    It = InstNumbers.find(I);
   210	
   211	    assert(It != InstNumbers.end() && "Didn't insert instruction?");
   212	    return It->second;
   213	  }
   214	
   215	  void deleteValue(const Instruction* I) { InstNumbers.erase(I); }
   216	
   217	  void clear() { InstNumbers.clear(); }
   218	};
